  "wrangler.public.toml": "name = \"public-gateway\"\nmain = \"src/public.js\"\ncompatibility_date = \"2024-12-01\"\n\n[[services]]\nbinding = \"AUTH_SERVICE\"\nservice = \"auth-service\"\n\n[[services]]\nbinding = \"PROFILE_SERVICE\"\nservice = \"profile-service\"\n\n[[services]]\nbinding = \"ORDER_SERVICE\"\nservice = \"order-service\"\n",
  "src/public.js": "export default {\n  async fetch(request, env) {\n    const url = new URL(request.url)\n    const requestId = crypto.randomUUID()\n\n    const baseHeaders = {\n      'x-request-id': requestId,\n      'x-forwarded-by': 'public-gateway'\n    }\n\n    if (url.pathname === '/health') {\n      return Response.json({ ok: true, service: 'public-gateway', requestId })\n    }\n\n    if (url.pathname.startsWith('/auth/')) {\n      const upstreamUrl = new URL(request.url)\n      upstreamUrl.pathname = url.pathname.replace(/^\\/auth/, '') || '/'\n      const upstreamRequest = new Request(upstreamUrl.toString(), request)\n      Object.entries(baseHeaders).forEach(([k, v]) => upstreamRequest.headers.set(k, v))\n      return env.AUTH_SERVICE.fetch(upstreamRequest)\n    }\n\n    if (url.pathname.startsWith('/profile/')) {\n      const upstreamUrl = new URL(request.url)\n      upstreamUrl.pathname = url.pathname.replace(/^\\/profile/, '') || '/'\n      const upstreamRequest = new Request(upstreamUrl.toString(), request)\n      Object.entries(baseHeaders).forEach(([k, v]) => upstreamRequest.headers.set(k, v))\n      return env.PROFILE_SERVICE.fetch(upstreamRequest)\n    }\n\n    if (url.pathname.startsWith('/orders/')) {\n      const upstreamUrl = new URL(request.url)\n      upstreamUrl.pathname = url.pathname.replace(/^\\/orders/, '') || '/'\n      const upstreamRequest = new Request(upstreamUrl.toString(), request)\n      Object.entries(baseHeaders).forEach(([k, v]) => upstreamRequest.headers.set(k, v))\n      return env.ORDER_SERVICE.fetch(upstreamRequest)\n    }\n\n    return new Response('Not Found', { status: 404 })\n  }\n}\n",
  "wrangler.auth.toml": "name = \"auth-service\"\nmain = \"src/auth.js\"\ncompatibility_date = \"2024-12-01\"\n\n[[services]]\nbinding = \"PROFILE_SERVICE\"\nservice = \"profile-service\"\n\n[[services]]\nbinding = \"ORDER_SERVICE\"\nservice = \"order-service\"\n",
  "src/auth.js": "function json(data, init = {}) {\n  const headers = new Headers(init.headers || {})\n  headers.set('content-type', 'application/json; charset=utf-8')\n  return new Response(JSON.stringify(data), { ...init, headers })\n}\n\nexport default {\n  async fetch(request, env) {\n    const url = new URL(request.url)\n    const requestId = request.headers.get('x-request-id') || crypto.randomUUID()\n\n    if (url.pathname === '/health') {\n      return json({ ok: true, service: 'auth-service', requestId })\n    }\n\n    if (url.pathname === '/login' && request.method === 'POST') {\n      const body = await request.json().catch(() => ({}))\n      const userId = body.userId || 'user_123'\n      return json({ ok: true, service: 'auth-service', requestId, token: `token-for-${userId}`, userId })\n    }\n\n    if (url.pathname === '/validate' && request.method === 'GET') {\n      const auth = request.headers.get('authorization') || ''\n      const valid = auth.startsWith('Bearer ')\n      return json({ ok: true, service: 'auth-service', requestId, valid })\n    }\n\n    if (url.pathname === '/user-context' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n\n      const profileReq = new Request(`https://profile.internal/internal/profile?userId=${encodeURIComponent(userId)}`, {\n        method: 'GET',\n        headers: { 'x-request-id': requestId, 'x-forwarded-by': 'auth-service' }\n      })\n      const ordersReq = new Request(`https://order.internal/internal/orders?userId=${encodeURIComponent(userId)}`, {\n        method: 'GET',\n        headers: { 'x-request-id': requestId, 'x-forwarded-by': 'auth-service' }\n      })\n\n      const [profileRes, ordersRes] = await Promise.all([\n        env.PROFILE_SERVICE.fetch(profileReq),\n        env.ORDER_SERVICE.fetch(ordersReq)\n      ])\n\n      const [profile, orders] = await Promise.all([\n        profileRes.json().catch(() => ({})),\n        ordersRes.json().catch(() => ({}))\n      ])\n\n      return json({ ok: true, service: 'auth-service', requestId, userId, profile, orders })\n    }\n\n    return json({ ok: false, error: 'Not Found', service: 'auth-service', requestId }, { status: 404 })\n  }\n}\n",
  "wrangler.profile.toml": "name = \"profile-service\"\nmain = \"src/profile.js\"\ncompatibility_date = \"2024-12-01\"\n\n[[services]]\nbinding = \"AUTH_SERVICE\"\nservice = \"auth-service\"\n\n[[services]]\nbinding = \"ORDER_SERVICE\"\nservice = \"order-service\"\n",
  "src/profile.js": "function json(data, init = {}) {\n  const headers = new Headers(init.headers || {})\n  headers.set('content-type', 'application/json; charset=utf-8')\n  return new Response(JSON.stringify(data), { ...init, headers })\n}\n\nexport default {\n  async fetch(request, env) {\n    const url = new URL(request.url)\n    const requestId = request.headers.get('x-request-id') || crypto.randomUUID()\n\n    if (url.pathname === '/health') {\n      return json({ ok: true, service: 'profile-service', requestId })\n    }\n\n    if (url.pathname === '/me' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      return json({ ok: true, service: 'profile-service', requestId, profile: { userId, name: 'Edge User', plan: 'pro' } })\n    }\n\n    if (url.pathname === '/internal/profile' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      return json({ ok: true, service: 'profile-service', requestId, profile: { userId, name: 'Edge User', plan: 'pro', region: 'global' } })\n    }\n\n    if (url.pathname === '/internal/profile-with-orders' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      const ordersReq = new Request(`https://order.internal/internal/orders?userId=${encodeURIComponent(userId)}`, {\n        method: 'GET',\n        headers: { 'x-request-id': requestId, 'x-forwarded-by': 'profile-service' }\n      })\n      const ordersRes = await env.ORDER_SERVICE.fetch(ordersReq)\n      const orders = await ordersRes.json().catch(() => ({}))\n      return json({\n        ok: true,\n        service: 'profile-service',\n        requestId,\n        profile: { userId, name: 'Edge User', plan: 'pro', region: 'global' },\n        orders\n      })\n    }\n\n    return json({ ok: false, error: 'Not Found', service: 'profile-service', requestId }, { status: 404 })\n  }\n}\n",
