  "src/order.js": "function json(data, init = {}) {\n  const headers = new Headers(init.headers || {})\n  headers.set('content-type', 'application/json; charset=utf-8')\n  return new Response(JSON.stringify(data), { ...init, headers })\n}\n\nexport default {\n  async fetch(request, env) {\n    const url = new URL(request.url)\n    const requestId = request.headers.get('x-request-id') || crypto.randomUUID()\n\n    if (url.pathname === '/health') {\n      return json({ ok: true, service: 'order-service', requestId })\n    }\n\n    if (url.pathname === '/list' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      return json({\n        ok: true,\n        service: 'order-service',\n        requestId,\n        orders: [\n          { id: 'ord_1', userId, total: 42.5, currency: 'USD', status: 'paid' },\n          { id: 'ord_2', userId, total: 13.37, currency: 'USD', status: 'processing' }\n        ]\n      })\n    }\n\n    if (url.pathname === '/internal/orders' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      return json({\n        ok: true,\n        service: 'order-service',\n        requestId,\n        orders: [\n          { id: 'ord_1', userId, total: 42.5, currency: 'USD', status: 'paid' },\n          { id: 'ord_2', userId, total: 13.37, currency: 'USD', status: 'processing' }\n        ]\n      })\n    }\n\n    if (url.pathname === '/internal/order-summary' && request.method === 'GET') {\n      const userId = url.searchParams.get('userId') || 'user_123'\n      const profileReq = new Request(`https://profile.internal/internal/profile?userId=${encodeURIComponent(userId)}`, {\n        method: 'GET',\n        headers: { 'x-request-id': requestId, 'x-forwarded-by': 'order-service' }\n      })\n      const profileRes = await env.PROFILE_SERVICE.fetch(profileReq)\n      const profile = await profileRes.json().catch(() => ({}))\n      return json({\n        ok: true,\n        service: 'order-service',\n        requestId,\n        summary: { userId, count: 2, total: 55.87, currency: 'USD' },\n        profile\n      })\n    }\n\n    return json({ ok: false, error: 'Not Found', service: 'order-service', requestId }, { status: 404 })\n  }\n}\n",
